Label f;

f.p=fontsize(4);

xaxis(-1,3,Ticks(f, 1.0));

yaxis(-4,3,Ticks(f, 1.0));

real f(real x)

{

return 5/3*(x-1)^2-11/3;

}

draw(graph(f,-1,3));
[/asy]

